import { SupabaseClient } from '@supabase/supabase-js'

export interface UserIdentity {
  id: string
  email: string
}

export class AuthModule {
  private supabase: SupabaseClient
  private providedUser?: UserIdentity
  private modal?: HTMLElement

  constructor(supabase: SupabaseClient, user?: UserIdentity) {
    this.supabase = supabase
    this.providedUser = user
  }

  async checkAuth(): Promise<boolean> {
    if (this.providedUser) {
      return true
    }

    const { data: { session } } = await this.supabase.auth.getSession()
    return !!session
  }

  async showLoginModal(): Promise<void> {
    return new Promise((resolve, reject) => {
      this.createLoginModal(resolve, reject)
    })
  }

  private createLoginModal(resolve: () => void, reject: (error: Error) => void): void {
    // Create modal backdrop
    const backdrop = document.createElement('div')
    backdrop.style.cssText = `
      position: fixed;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background: rgba(0, 0, 0, 0.5);
      z-index: 999999;
      display: flex;
      align-items: center;
      justify-content: center;
    `

    // Create modal content
    const modal = document.createElement('div')
    modal.style.cssText = `
      background: white;
      border-radius: 8px;
      padding: 24px;
      max-width: 400px;
      width: 90%;
      box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1);
    `

    // Create form
    const form = document.createElement('form')
    form.innerHTML = `
      <h2 style="margin: 0 0 16px 0; font-size: 20px; font-weight: 600;">Sign in to Vibe Viewer</h2>
      <p style="margin: 0 0 20px 0; color: #666; font-size: 14px;">Enter your email to receive a magic link</p>
      <input
        type="email"
        placeholder="Enter your email"
        required
        style="
          width: 100%;
          padding: 12px;
          border: 1px solid #ddd;
          border-radius: 4px;
          margin-bottom: 16px;
          box-sizing: border-box;
          font-size: 14px;
        "
      />
      <div style="display: flex; gap: 12px;">
        <button
          type="submit"
          style="
            flex: 1;
            background: #000;
            color: white;
            border: none;
            padding: 12px;
            border-radius: 4px;
            cursor: pointer;
            font-size: 14px;
          "
        >Send Magic Link</button>
        <button
          type="button"
          class="cancel"
          style="
            background: #f5f5f5;
            color: #666;
            border: none;
            padding: 12px 20px;
            border-radius: 4px;
            cursor: pointer;
            font-size: 14px;
          "
        >Cancel</button>
      </div>
    `

    // Handle form submission
    form.addEventListener('submit', async (e) => {
      e.preventDefault()
      const email = (form.querySelector('input[type="email"]') as HTMLInputElement).value

      try {
        const { error } = await this.supabase.auth.signInWithOtp({
          email,
          options: {
            emailRedirectTo: window.location.href
          }
        })

        if (error) throw error

        // Show success message
        modal.innerHTML = `
          <h2 style="margin: 0 0 16px 0; font-size: 20px; font-weight: 600;">Check your email</h2>
          <p style="margin: 0 0 20px 0; color: #666; font-size: 14px;">
            We've sent a magic link to <strong>${email}</strong>.
            Click the link in the email to sign in.
          </p>
          <button
            class="close"
            style="
              width: 100%;
              background: #000;
              color: white;
              border: none;
              padding: 12px;
              border-radius: 4px;
              cursor: pointer;
              font-size: 14px;
            "
          >Close</button>
        `

        // Handle close button
        modal.querySelector('.close')?.addEventListener('click', () => {
          document.body.removeChild(backdrop)
          resolve()
        })

      } catch (error) {
        alert('Error sending magic link: ' + (error as Error).message)
        reject(error as Error)
      }
    })

    // Handle cancel button
    form.querySelector('.cancel')?.addEventListener('click', () => {
      document.body.removeChild(backdrop)
      reject(new Error('Login cancelled'))
    })

    // Close modal on backdrop click
    backdrop.addEventListener('click', (e) => {
      if (e.target === backdrop) {
        document.body.removeChild(backdrop)
        reject(new Error('Login cancelled'))
      }
    })

    modal.appendChild(form)
    backdrop.appendChild(modal)
    document.body.appendChild(backdrop)

    this.modal = backdrop
  }

  async getCurrentUser(): Promise<UserIdentity | null> {
    if (this.providedUser) {
      return this.providedUser
    }

    // Get user from Supabase session
    const { data: { session } } = await this.supabase.auth.getSession()
    if (session?.user) {
      return {
        id: session.user.id,
        email: session.user.email || ''
      }
    }

    return null
  }
}