import { createClient, SupabaseClient } from '@supabase/supabase-js'
import { AuthModule } from './auth'
import { OverlayModule } from './overlay'
import { ToolbarModule, ToolbarConfig } from './toolbar'
import { CommentListModule } from './commentList'

export interface VibeConfig {
  supabaseUrl: string
  supabaseAnonKey: string
  projectId: string
  user?: {
    id: string
    email: string
  }
}

export class VibeInstance {
  private supabase: SupabaseClient
  private auth: AuthModule
  private overlay: OverlayModule
  private toolbar?: ToolbarModule
  private commentList?: CommentListModule
  private config: VibeConfig
  private isActive = false

  constructor(config: VibeConfig) {
    this.config = config
    this.supabase = createClient(config.supabaseUrl, config.supabaseAnonKey)
    this.auth = new AuthModule(this.supabase, config.user)
    this.overlay = new OverlayModule(this.supabase, config.projectId)
  }

  async activate(): Promise<void> {
    if (this.isActive) return

    // Check if user is authenticated
    if (!this.config.user) {
      const isAuthenticated = await this.auth.checkAuth()
      if (!isAuthenticated) {
        await this.auth.showLoginModal()
        return
      }
    }

    // Initialize overlay
    await this.overlay.init()

    // Initialize toolbar if in agentic mode
    this.toolbar = new ToolbarModule(this.supabase, {
      position: 'bottom-right',
      user: this.config.user,
      projectId: this.config.projectId
    })
    await this.toolbar.init()

    // Initialize comment list
    this.commentList = new CommentListModule(this.supabase, {
      projectId: this.config.projectId,
      currentUser: this.config.user
    })

    // Set up toolbar event handlers
    this.setupEventHandlers()

    this.isActive = true
  }

  destroy(): void {
    if (this.overlay) {
      this.overlay.destroy()
    }
    if (this.toolbar) {
      this.toolbar.destroy()
    }
    if (this.commentList) {
      this.commentList.hide()
    }
    this.isActive = false
  }

  private setupEventHandlers(): void {
    // Handle opening comment list from toolbar
    window.addEventListener('vibe:openCommentsList', () => {
      if (this.commentList) {
        this.commentList.show()
      }
    })

    // Handle comment updates to refresh toolbar
    window.addEventListener('vibe:commentUpdated', () => {
      if (this.toolbar) {
        this.toolbar.refresh()
      }
    })
  }

  getSupabaseClient(): SupabaseClient {
    return this.supabase
  }

  getToolbar(): ToolbarModule | undefined {
    return this.toolbar
  }

  getCommentList(): CommentListModule | undefined {
    return this.commentList
  }
}

export function initVibe(config: VibeConfig): VibeInstance {
  const instance = new VibeInstance(config)

  // Auto-activate if ?agentic=true is in URL
  if (typeof window !== 'undefined') {
    const urlParams = new URLSearchParams(window.location.search)
    if (urlParams.get('agentic') === 'true') {
      instance.activate().catch(console.error)
    }
  }

  return instance
}

